const text = $input.first().json.responses?.[0]?.fullTextAnnotation?.text || '';

const FACHRICHTUNGEN = [
  'Orthopädie', 'Dermatologie', 'Neurologie', 'Kardiologie',
  'Psychiatrie', 'Urologie', 'HNO', 'Augenheilkunde',
  'Gynäkologie', 'Innere Medizin', 'Chirurgie', 'Radiologie'
];

const specialtyFound = FACHRICHTUNGEN.find(f =>
  text.toLowerCase().includes(f.toLowerCase())
) || '';

const dringend = /dring|urgent|sofort|D\b/i.test(text);

const gkvMatch = text.match(/GKV|gesetzlich|Krankenkasse/i);
const pkvMatch = text.match(/PKV|privat/i);
const insurance = pkvMatch ? 'pkv' : gkvMatch ? 'gkv' : 'gkv';

const arztMatch = text.match(/Dr\.?\s+[A-Z][a-zäöüß]+(?:\s+[A-Z][a-zäöüß]+)?/);
const issuerDoctor = arztMatch ? arztMatch[0] : '';

return [{
  json: {
    success: true,
    rawText: text,
    specialty: specialtyFound,
    urgent: dringend,
    insurance,
    issuerDoctor,
    confidence: specialtyFound ? 0.9 : 0.3
  }
}];
